{
  "grammar": [
    {
      "pattern": "Subject + 穿 + Number + 號 / 尺寸",
      "structure": ["Subject", "穿", "Number", "號/尺寸"],
      "explanation_en": "Use this pattern to ask or state what size someone wears. '號' is common for shoes, '尺寸' for general clothing.",
      "title": "Asking About Size",
      "meaning": "Asking or stating clothing size",
      "when_to_use": ["When you want to ask someone's size", "When you want to say your own size"],
      "when_not_to_use": ["Do not use for food or drinks", "Do not use for abstract measurements"],
      "pragmatic_notes": "In Taiwan, sizes are often labeled as S, M, L, XL, or numbers like 36, 38. '尺寸' is more formal.",
      "word_order_notes": "The size word comes after the verb '穿'.",
      "english_contrast": "English uses 'What size do you wear?' while Chinese uses '你穿幾號？'.",
      "korean_contrast": "Korean uses '사이즈가 어떻게 되세요?' while Chinese uses '你穿什麼尺寸？'.",
      "negative_examples": [
        {
          "text": "你穿尺寸什麼？",
          "error": "Word order is wrong; '什麼尺寸' should come after '穿'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你穿什麼尺寸？",
          "error": "This is actually correct. No error."
        }
      ],
      "transformation_drills": ["Change '你穿幾號？' to '你穿什麼尺寸？'"],
      "production_drills": ["Ask your partner what size they wear."],
      "common_error_patterns": ["Placing '什麼' before '尺寸' incorrectly"],
      "repair_feedback": {
        "word_order": "Put '什麼尺寸' after '穿'.",
        "politeness": "Use '請問' to make it polite.",
        "vocabulary": "Use '尺寸' for general clothing, '號' for shoes."
      }
    },
    {
      "pattern": "Subject + 太 + Adjective + 了",
      "structure": ["Subject", "太", "Adjective", "了"],
      "explanation_en": "Use this pattern to express that something is excessively adjective. It often implies a problem or complaint.",
      "title": "Expressing Excessiveness with 太...了",
      "meaning": "Too (adjective)",
      "when_to_use": ["When something is too big, small, expensive, etc.", "When you want to complain politely"],
      "when_not_to_use": ["Do not use for positive excess (e.g., 'too good' is rare)", "Do not use without '了' at the end"],
      "pragmatic_notes": "In Taiwan, this is very common in shopping to express dissatisfaction. It softens the complaint.",
      "word_order_notes": "The adjective comes between '太' and '了'.",
      "english_contrast": "English uses 'too + adjective', Chinese uses '太 + adjective + 了'.",
      "korean_contrast": "Korean uses '너무 + adjective', Chinese uses '太 + adjective + 了'.",
      "negative_examples": [
        {
          "text": "這件衣服太貴。",
          "error": "Missing '了' at the end."
        }
      ],
      "incorrect_examples": [
        {
          "text": "這件衣服太貴了。",
          "error": "This is correct."
        }
      ],
      "transformation_drills": ["Change '這件衣服很大' to '這件衣服太大了'"],
      "production_drills": ["Complain that the shoes are too small."],
      "common_error_patterns": ["Omitting '了'", "Using '太' with positive adjectives without context"],
      "repair_feedback": {
        "word_order": "Keep '太' before the adjective and '了' at the end.",
        "politeness": "Use '不好意思' before complaining.",
        "vocabulary": "Use adjectives like '大', '小', '貴', '便宜'."
      }
    },
    {
      "pattern": "Subject + 有沒有 + Size/Color + 的 + Noun",
      "structure": ["Subject", "有沒有", "Size/Color", "的", "Noun"],
      "explanation_en": "Use this pattern to ask if a certain size or color is available. It's a yes/no question.",
      "title": "Asking About Availability of Size/Color",
      "meaning": "Do you have (size/color) of (item)?",
      "when_to_use": ["When you want to ask if a specific size exists", "When you want to ask if a specific color exists"],
      "when_not_to_use": ["Do not use for asking about price", "Do not use for asking about location"],
      "pragmatic_notes": "In Taiwan, this is very common in clothing stores. You can also use '有...嗎？' but '有沒有' is more direct.",
      "word_order_notes": "The size/color comes before '的' and the noun.",
      "english_contrast": "English uses 'Do you have this in size...?' while Chinese uses '有沒有...的...？'.",
      "korean_contrast": "Korean uses '...사이즈 있어요?' while Chinese uses '有沒有...的...？'.",
      "negative_examples": [
        {
          "text": "你有沒有衣服的黑色？",
          "error": "Word order is wrong; '黑色' should come before '的'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "你有沒有黑色的衣服？",
          "error": "This is correct."
        }
      ],
      "transformation_drills": ["Change '你有黑色的衣服嗎？' to '你有沒有黑色的衣服？'"],
      "production_drills": ["Ask if the store has a blue shirt in size M."],
      "common_error_patterns": ["Placing the noun before the size/color", "Forgetting '的'"],
      "repair_feedback": {
        "word_order": "Put size/color before '的' and the noun after.",
        "politeness": "Add '請問' at the beginning.",
        "vocabulary": "Use colors like '黑色', '白色', '紅色' and sizes like '小號', '中號', '大號'."
      }
    }
  ]
}
